import subprocess,os,base64,datetime,urllib.request,json,time
P1='192.168.10.19'
WEB='/var/www/html'
MP='/mnt/vnt-data/FileServer/VNT_World_AI_Division/MemPalace.md'
CFG='/mnt/vnt-data/FileServer/VNT_World_AI_Division/vnt_config.json'
TSF=datetime.datetime.now().strftime('%Y%m%d_%H%M')

# Embedded HTML (26k chars, no secrets)
CHUNKS=[
    '',
    '',
    '',
    '',
    '',
    '',
    '',
    '',
]
html_data=base64.b64decode(''.join(CHUNKS))

def rx(host,cmd,t=30):
    r=subprocess.run(['ssh','-o','StrictHostKeyChecking=no','-o','ConnectTimeout=8','root@'+host,cmd],capture_output=True,text=True,timeout=t)
    return (r.stdout+r.stderr).strip()

def pct_e(ctid,cmd,t=60):
    r=subprocess.run(['ssh','-o','StrictHostKeyChecking=no','-o','ConnectTimeout=8','root@'+P1,'pct exec '+str(ctid)+' -- bash -c '+json.dumps(cmd)],capture_output=True,text=True,timeout=t)
    return (r.stdout+r.stderr).strip()

def save(e):
    try: open(MP,'a').write('\n### CT108 ['+TSF+']\n'+e+'\n')
    except: pass

print('='*55)
print('DEPLOY CT108 DASHBOARD v2')
print(TSF)
print('='*55)

# Update vnt_config with correct production info
try:
    cfg=json.load(open(CFG))
except: cfg={}
cfg.update({'production_web_ct':'108','production_web_root':WEB,'production_domain':'vntworld.com','never_write_to':'/home/k/vnt-web','updated':TSF})
json.dump(cfg,open(CFG,'w'),indent=2)
print('[CFG] vnt_config updated with production facts')

# Check CT108
print('[1] CT108 status...')
st=rx(P1,'pct status 108')
print(' ',st)
if 'stopped' in st.lower():
    rx(P1,'pct start 108',t=20);time.sleep(8)

print(f'[2] HTML ready: {len(html_data)} bytes')

# BACKUP
print('[3] Backup...')
bk=pct_e(108,f'cp {WEB}/dashboard.html {WEB}/dashboard.html.bak_{TSF} && echo OK')
print(' ',bk)
rx(P1,f'mkdir -p /root/ct108_backups && pct pull 108 {WEB}/dashboard.html /root/ct108_backups/dashboard_{TSF}.html',t=20)

# Write HTML via pct push
print('[4] Writing to CT108...')
open('/tmp/new_dashboard.html','wb').write(html_data)
push_r=rx(P1,f'pct push 108 /tmp/new_dashboard.html {WEB}/dashboard.html',t=30)
print(' pct push:',push_r or 'OK')

# Verify file size
verify=pct_e(108,f'wc -c {WEB}/dashboard.html')
print('[5] Verify:',verify[:100])

# Check it has the new content
check=pct_e(108,f'grep -c GAMES {WEB}/dashboard.html 2>/dev/null || echo 0')
print('[6] GAMES in file:',check)

# Nginx reload
reload=pct_e(108,'nginx -t 2>&1 && nginx -s reload 2>&1 || service nginx reload 2>&1')
print('[7] Nginx:',reload[:100])

save('\n'.join([
    'CT108 v2 deployed '+TSF,
    'Backup: '+WEB+'/dashboard.html.bak_'+TSF,
    'Prox1: /root/ct108_backups/dashboard_'+TSF+'.html',
    'ROLLBACK: pct exec 108 -- bash -c cp '+WEB+'/dashboard.html.bak_'+TSF+' '+WEB+'/dashboard.html',
]))

print('='*55)
print('DONE: vntworld.com/dashboard.html updated')
print(f'Rollback: pct exec 108 -- bash -c "cp {WEB}/dashboard.html.bak_{TSF} {WEB}/dashboard.html"')
print('='*55)